# Create customer segments based on multiple dimensions
# We'll use: activity status, spending level, tenure, and plan tier

# Define spending categories (based on cleaned spend)
def categorize_spend(spend):
    if spend == 0:
        return 'No Spend'
    elif spend < 15:
        return 'Low Spend'
    elif spend < 50:
        return 'Medium Spend'
    elif spend < 100:
        return 'High Spend'
    else:
        return 'Very High Spend'

df['spend_category'] = df['monthly_spend_clean'].apply(categorize_spend)

# Define tenure categories
def categorize_tenure(months):
    if months < 3:
        return 'New'
    elif months < 12:
        return 'Growing'
    elif months < 24:
        return 'Established'
    else:
        return 'Veteran'

df['tenure_category'] = df['tenure_months'].apply(categorize_tenure)

# Create comprehensive segments
def create_segment(row):
    # High-value segments
    if row['plan_tier'] == 'enterprise':
        if row['is_active']:
            return 'Champions (Enterprise)'
        else:
            return 'At-Risk Enterprise'

    if row['plan_tier'] == 'premium':
        if row['is_active'] and row['monthly_spend_clean'] > 50:
            return 'Loyal Premium'
        elif row['is_active']:
            return 'Active Premium'
        else:
            return 'At-Risk Premium'

    # Mid-tier segments
    if row['plan_tier'] == 'basic':
        if row['is_active'] and row['monthly_spend_clean'] > 10:
            return 'Engaged Basic'
        elif row['is_active']:
            return 'Active Basic'
        else:
            return 'Churned Basic'

    # Free tier segments
    if row['plan_tier'] == 'free':
        if row['is_active'] and row['monthly_spend_clean'] > 0:
            return 'Converting Free'
        elif row['is_active']:
            return 'Active Free'
        else:
            return 'Inactive Free'

    return 'Other'

df['segment'] = df.apply(create_segment, axis=1)

print("Segment distribution:")
segment_summary = df['segment'].value_counts()
print(segment_summary)
